'use client';
import React, { useState, useEffect, useRef } from 'react';
import { Bluetooth, Heart, Zap, Activity, Play, Pause, Plus, Trash2, Settings, Monitor, Save, Edit3, Clock, BarChart2, X, ChevronLeft, RotateCcw, Home, Gauge, Sliders, ArrowRight } from 'lucide-react';
import { bleService } from '@/services/bleService';
import { TrainerData, HeartRateData, ControlMode, Workout, WorkoutSessionState, IntervalStep } from '@/types';
import { ResponsiveContainer, AreaChart, Area, LineChart, Line, XAxis, YAxis, Tooltip, CartesianGrid } from 'recharts';

// --- Constants & Helpers ---

const FTP_DEFAULT = 200;

// Joe Friel / Coggan Power Zones with Gradient Definitions
const ZONES = [
  { name: 'Z1', label: 'Recovery',        min: 0, max: 0.55, color: '#94a3b8', gradient: ['#94a3b8', '#cbd5e1'], desc: '< 55%' },
  { name: 'Z2', label: 'Endurance',       min: 0.56, max: 0.75, color: '#06b6d4', gradient: ['#06b6d4', '#67e8f9'], desc: '56-75%' }, 
  { name: 'Z3', label: 'Tempo',           min: 0.76, max: 0.90, color: '#10b981', gradient: ['#10b981', '#6ee7b7'], desc: '76-90%' }, 
  { name: 'Z4', label: 'Threshold',       min: 0.91, max: 1.05, color: '#f59e0b', gradient: ['#f59e0b', '#fcd34d'], desc: '91-105%' }, 
  { name: 'Z5', label: 'VO2 Max',         min: 1.06, max: 1.20, color: '#ef4444', gradient: ['#ef4444', '#fca5a5'], desc: '106-120%' }, 
  { name: 'Z6', label: 'Anaerobic',       min: 1.21, max: 2.50, color: '#8b5cf6', gradient: ['#8b5cf6', '#c4b5fd'], desc: '> 121%' }, 
];

const getZoneColor = (watts: number, ftp: number) => {
  const ratio = watts / ftp;
  const zone = ZONES.find(z => ratio <= z.max) || ZONES[ZONES.length - 1];
  return zone;
};

const formatTime = (seconds: number) => {
  const m = Math.floor(seconds / 60);
  const s = seconds % 60;
  return `${m}:${s < 10 ? '0' : ''}${s}`;
};

type ViewState = 'HOME' | 'FREE_RIDE' | 'ERG_MODE' | 'EDITOR' | 'SESSION';

// --- Styled Components (Functional) ---

const Card = ({ children, className = '', onClick, glow = false }: { children: React.ReactNode, className?: string, onClick?: () => void, glow?: boolean }) => (
  <div 
    onClick={onClick}
    className={`
      relative overflow-hidden
      bg-idx-surface/40 backdrop-blur-xl border border-white/10 rounded-3xl 
      transition-all duration-500 ease-out
      ${onClick ? 'cursor-pointer hover:bg-idx-surface/60 hover:border-white/20 hover:shadow-2xl hover:shadow-neon-blue/10 hover:-translate-y-1' : ''} 
      ${glow ? 'shadow-[0_0_40px_-10px_rgba(59,130,246,0.15)] border-white/10' : 'shadow-xl'}
      ${className}
    `}
  >
    {/* Inner highlight for glass effect */}
    <div className="absolute inset-0 bg-gradient-to-br from-white/5 to-transparent pointer-events-none opacity-50"></div>
    {children}
  </div>
);

const GradientText = ({ children, className = '' }: { children: React.ReactNode, className?: string }) => (
  <span className={`bg-clip-text text-transparent bg-gradient-to-r from-neon-cyan via-neon-blue to-neon-purple font-extrabold tracking-tight ${className}`}>
    {children}
  </span>
);

const Button = ({ children, onClick, variant = 'primary', className = '', disabled = false }: any) => {
  const base = "relative overflow-hidden rounded-2xl font-bold transition-all duration-300 flex items-center justify-center gap-2 shadow-lg disabled:opacity-50 disabled:cursor-not-allowed active:scale-95";
  const styles = {
    primary: "bg-gradient-to-r from-neon-blue to-neon-purple text-white hover:brightness-110 shadow-neon-blue/25 hover:shadow-neon-blue/50 border border-white/20",
    secondary: "bg-white/5 border border-white/10 text-gray-300 hover:text-white hover:bg-white/10 hover:border-white/20 backdrop-blur-md",
    danger: "bg-red-500/10 text-red-400 border border-red-500/20 hover:bg-red-500/20 hover:border-red-500/50 hover:shadow-red-500/20",
    neon: "bg-transparent border border-neon-cyan/30 text-neon-cyan shadow-[0_0_15px_rgba(6,182,212,0.1)] hover:shadow-[0_0_25px_rgba(6,182,212,0.3)] hover:bg-neon-cyan/5 hover:border-neon-cyan"
  };
  
  return (
    <button onClick={onClick} disabled={disabled} className={`${base} ${styles[variant as keyof typeof styles]} ${className}`}>
      {children}
    </button>
  );
};

function App() {
  // --- Global State ---
  const [view, setView] = useState<ViewState>('HOME');
  const [isTrainerConnected, setIsTrainerConnected] = useState(false);
  const [isHRConnected, setIsHRConnected] = useState(false);
  const [trainerData, setTrainerData] = useState<TrainerData>({ power: 0, cadence: 0, speed: 0 });
  const [hrData, setHrData] = useState<HeartRateData>({ heartRate: 0 });
  const [history, setHistory] = useState<{time: string, power: number, cadence: number, heartRate: number}[]>([]);
  const [ftp, setFtp] = useState(FTP_DEFAULT);
  const [resistanceLevel, setResistanceLevel] = useState(1);
  const [targetPower, setTargetPower] = useState(150);
  const [workout, setWorkout] = useState<Workout>({
    id: 'custom-1', name: 'Neon Intervals', description: 'High intensity neon workout.',
    author: 'User', tags: [], steps: [], totalDuration: 0
  });
  const [session, setSession] = useState<WorkoutSessionState>({
    isActive: false, currentStepIndex: 0, elapsedTimeInStep: 0, totalElapsedTime: 0, isPaused: false
  });
  const [selectedStepId, setSelectedStepId] = useState<string | null>(null);
  const [isConfirmingClear, setIsConfirmingClear] = useState(false);
  const timerRef = useRef<number | null>(null);

  // --- Effects ---
  useEffect(() => {
    bleService.setCallbacks(
      (data) => setTrainerData(data),
      (data) => setHrData(data)
    );
  }, []);

  useEffect(() => {
    const total = workout.steps.reduce((acc, step) => acc + step.duration, 0);
    setWorkout(w => ({ ...w, totalDuration: total }));
  }, [workout.steps]);

  useEffect(() => {
    if (isConfirmingClear) {
        const timer = setTimeout(() => setIsConfirmingClear(false), 3000);
        return () => clearTimeout(timer);
    }
  }, [isConfirmingClear]);

  useEffect(() => {
    const interval = setInterval(() => {
        setHistory(prev => {
            const now = new Date();
            const timeLabel = `${now.getSeconds()}`;
            const newPoint = {
                time: timeLabel,
                power: trainerData.power,
                cadence: trainerData.cadence,
                heartRate: hrData.heartRate || 0
            };
            const newHistory = [...prev, newPoint];
            return newHistory.length > 60 ? newHistory.slice(newHistory.length - 60) : newHistory;
        });
    }, 1000);
    return () => clearInterval(interval);
  }, [trainerData.power, trainerData.cadence, hrData.heartRate]);

  useEffect(() => {
    if (session.isActive && !session.isPaused) {
      timerRef.current = window.setInterval(() => {
        setSession(prev => {
          const currentStep = workout.steps[prev.currentStepIndex];
          if (prev.elapsedTimeInStep >= currentStep.duration) {
            const nextIndex = prev.currentStepIndex + 1;
            if (nextIndex >= workout.steps.length) {
              if (timerRef.current) clearInterval(timerRef.current);
              bleService.setTargetPower(100);
              setView('HOME');
              return { ...prev, isActive: false, isPaused: false };
            }
            const nextStep = workout.steps[nextIndex];
            const power = nextStep.type === 'ramp' && nextStep.startPower ? nextStep.startPower : nextStep.targetPower;
            bleService.setTargetPower(power);
            return { ...prev, currentStepIndex: nextIndex, elapsedTimeInStep: 0, totalElapsedTime: prev.totalElapsedTime + 1 };
          }
          if (currentStep.type === 'ramp' && currentStep.startPower) {
             const progress = prev.elapsedTimeInStep / currentStep.duration;
             const range = currentStep.targetPower - currentStep.startPower;
             const currentRampPower = Math.round(currentStep.startPower + (range * progress));
             if (prev.elapsedTimeInStep % 2 === 0) bleService.setTargetPower(currentRampPower);
          }
          return { ...prev, elapsedTimeInStep: prev.elapsedTimeInStep + 1, totalElapsedTime: prev.totalElapsedTime + 1 };
        });
      }, 1000);
    } else {
      if (timerRef.current) clearInterval(timerRef.current);
    }
    return () => { if (timerRef.current) clearInterval(timerRef.current); };
  }, [session.isActive, session.isPaused, workout.steps]);

  // --- Handlers ---
  const handleConnectTrainer = async () => {
    if (isTrainerConnected) { await bleService.disconnectTrainer(); setIsTrainerConnected(false); } 
    else { const success = await bleService.connectTrainer(); setIsTrainerConnected(success); }
  };
  const handleConnectHR = async () => {
     if (isHRConnected) { await bleService.disconnectHeartRate(); setIsHRConnected(false); } 
     else { const success = await bleService.connectHeartRate(); setIsHRConnected(success); }
  };
  const updateResistance = (level: number) => { setResistanceLevel(level); bleService.setResistance(level); };
  const updateTargetPower = (watts: number) => { setTargetPower(watts); bleService.setTargetPower(watts); };

  // --- Components ---

  const LiveGraph = () => (
    <Card className="w-full h-64 p-6 relative group border-white/10 bg-black/40" glow>
      {/* Background Grid Accent */}
      <div className="absolute inset-0 bg-[url('https://grainy-gradients.vercel.app/noise.svg')] opacity-10 mix-blend-overlay"></div>
      
      <div className="flex justify-between items-center mb-6 relative z-10">
        <h3 className="text-[10px] font-mono font-extrabold text-neon-blue/80 uppercase tracking-[0.2em] flex items-center gap-2">
           <Activity size={14} className="text-neon-blue"/> Live Telemetry
        </h3>
        <div className="flex gap-4">
          {[
            { label: 'PWR', color: '#3b82f6', val: trainerData.power }, 
            { label: 'RPM', color: '#06b6d4', val: Math.round(trainerData.cadence) }, 
            { label: 'HR', color: '#ec4899', val: hrData.heartRate }
          ].map(m => (
             <div key={m.label} className="flex items-center gap-2 bg-white/5 px-2 py-1 rounded-lg border border-white/5">
                <span className="w-1.5 h-1.5 rounded-full shadow-[0_0_8px_currentColor]" style={{ backgroundColor: m.color, color: m.color }}></span>
                <span className="text-xs font-mono text-gray-400">{m.label} <span className="text-white font-bold ml-1">{m.val}</span></span>
             </div>
          ))}
        </div>
      </div>
      
      <div className="w-full h-full pb-6">
        <ResponsiveContainer width="100%" height="100%">
           <LineChart data={history}>
              <Tooltip 
                 contentStyle={{backgroundColor: '#09090b', border: '1px solid #27272a', borderRadius: '12px', boxShadow: '0 10px 30px -10px rgba(0,0,0,0.8)'}}
                 itemStyle={{fontFamily: 'JetBrains Mono', fontSize: '12px', fontWeight: 'bold'}}
                 labelStyle={{display: 'none'}}
                 cursor={{stroke: 'rgba(255,255,255,0.1)', strokeWidth: 2}}
              />
              <YAxis domain={[0, 'auto']} hide />
              <Line 
                type="monotone" 
                dataKey="power" 
                stroke="#3b82f6" 
                strokeWidth={3} 
                dot={false} 
                activeDot={{r: 6, fill: '#fff', stroke: '#3b82f6', strokeWidth: 2, filter: 'drop-shadow(0 0 4px #3b82f6)'}}
                style={{ filter: 'drop-shadow(0 0 8px rgba(59, 130, 246, 0.6))' }}
                animationDuration={300}
              />
              <Line 
                type="monotone" 
                dataKey="cadence" 
                stroke="#06b6d4" 
                strokeWidth={2} 
                dot={false} 
                style={{ filter: 'drop-shadow(0 0 8px rgba(6, 182, 212, 0.4))' }}
                animationDuration={300}
              />
              <Line 
                type="monotone" 
                dataKey="heartRate" 
                stroke="#ec4899" 
                strokeWidth={2} 
                dot={false} 
                style={{ filter: 'drop-shadow(0 0 8px rgba(236, 72, 153, 0.4))' }}
                animationDuration={300}
              />
           </LineChart>
        </ResponsiveContainer>
      </div>
    </Card>
  );

  const StatBox = ({ label, value, unit, color }: any) => (
    <Card className="p-6 flex flex-col items-center justify-center relative overflow-hidden h-32" glow>
      <div className={`absolute -top-12 -right-12 w-32 h-32 rounded-full opacity-20 blur-3xl`} style={{ backgroundColor: color }}></div>
      <div className={`absolute -bottom-12 -left-12 w-32 h-32 rounded-full opacity-10 blur-3xl`} style={{ backgroundColor: color }}></div>
      
      <span className="text-[10px] font-mono font-bold text-gray-400 uppercase tracking-widest z-10">{label}</span>
      <div className="mt-1 flex items-baseline gap-1 z-10">
        <span className="text-5xl font-mono font-bold text-white tracking-tighter drop-shadow-lg">{value}</span>
        <span className="text-sm font-bold text-gray-500">{unit}</span>
      </div>
    </Card>
  );

  // --- Views ---

  const renderHome = () => (
    <div className="flex flex-col items-center justify-center h-full animate-fade-in w-full max-w-7xl mx-auto relative z-10">
      {/* Ambient Background Blobs specific to Home */}
      <div className="absolute top-0 left-1/4 w-[500px] h-[500px] bg-neon-purple/20 rounded-full blur-[120px] -z-10 animate-pulse-slow mix-blend-screen"></div>
      <div className="absolute bottom-0 right-1/4 w-[500px] h-[500px] bg-neon-blue/20 rounded-full blur-[120px] -z-10 animate-pulse-slow mix-blend-screen" style={{animationDelay: '2s'}}></div>

      <div className="text-center mb-16 relative">
        <h1 className="text-5xl md:text-7xl font-black mb-6 tracking-tight text-white drop-shadow-2xl">
          Your training, <br className="md:hidden" /> <GradientText>your way</GradientText>
        </h1>
        <p className="text-lg md:text-xl text-gray-400 font-medium max-w-lg mx-auto leading-relaxed">
           Connect your smart trainer. Build your legacy.
        </p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6 w-full max-w-4xl mb-16 px-4">
          {/* Trainer Connect */}
          <Card className={`p-8 flex items-center justify-between border-l-[6px] ${isTrainerConnected ? 'border-l-neon-green bg-gradient-to-r from-neon-green/5 to-transparent' : 'border-l-gray-700'} hover:scale-[1.02]`}>
              <div className="flex items-center gap-6">
                  <div className={`w-16 h-16 rounded-2xl flex items-center justify-center transition-all ${isTrainerConnected ? 'bg-neon-green/20 text-neon-green shadow-[0_0_20px_rgba(16,185,129,0.3)] ring-1 ring-neon-green/50' : 'bg-white/5 text-gray-500'}`}>
                      <Zap size={32} strokeWidth={isTrainerConnected ? 2.5 : 2} />
                  </div>
                  <div>
                      <h3 className="font-bold text-white text-xl">Smart Trainer</h3>
                      <div className="flex items-center gap-2 mt-2">
                          <span className={`w-2 h-2 rounded-full ${isTrainerConnected ? 'bg-neon-green shadow-[0_0_10px_#10b981] animate-pulse' : 'bg-gray-600'}`}></span>
                          <span className={`text-sm font-mono font-medium ${isTrainerConnected ? 'text-neon-green' : 'text-gray-500'}`}>{isTrainerConnected ? 'CONNECTED' : 'OFFLINE'}</span>
                      </div>
                  </div>
              </div>
              <Button 
                variant={isTrainerConnected ? 'secondary' : 'neon'} 
                onClick={handleConnectTrainer}
                className="px-8 py-3 text-sm"
              >
                  {isTrainerConnected ? 'Disconnect' : 'Connect'}
              </Button>
          </Card>

          {/* HR Connect */}
          <Card className={`p-8 flex items-center justify-between border-l-[6px] ${isHRConnected ? 'border-l-neon-pink bg-gradient-to-r from-neon-pink/5 to-transparent' : 'border-l-gray-700'} hover:scale-[1.02]`}>
              <div className="flex items-center gap-6">
                  <div className={`w-16 h-16 rounded-2xl flex items-center justify-center transition-all ${isHRConnected ? 'bg-neon-pink/20 text-neon-pink shadow-[0_0_20px_rgba(236,72,153,0.3)] ring-1 ring-neon-pink/50' : 'bg-white/5 text-gray-500'}`}>
                      <Heart size={32} strokeWidth={isHRConnected ? 2.5 : 2} />
                  </div>
                  <div>
                      <h3 className="font-bold text-white text-xl">Heart Rate</h3>
                      <div className="flex items-center gap-2 mt-2">
                          <span className={`w-2 h-2 rounded-full ${isHRConnected ? 'bg-neon-pink shadow-[0_0_10px_#ec4899] animate-pulse' : 'bg-gray-600'}`}></span>
                          <span className={`text-sm font-mono font-medium ${isHRConnected ? 'text-neon-pink' : 'text-gray-500'}`}>{isHRConnected ? 'CONNECTED' : 'OFFLINE'}</span>
                      </div>
                  </div>
              </div>
              <Button 
                variant={isHRConnected ? 'secondary' : 'neon'} 
                onClick={handleConnectHR}
                className="px-8 py-3 text-sm"
              >
                  {isHRConnected ? 'Disconnect' : 'Connect'}
              </Button>
          </Card>
      </div>
      
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6 w-full px-4 max-w-7xl">
        {[
          { id: 'FREE_RIDE', icon: Gauge, title: 'Free Ride', desc: 'Manual slope control.', color: 'text-neon-cyan', gradient: 'from-neon-cyan/20 to-transparent' },
          { id: 'ERG_MODE', icon: Zap, title: 'ERG Mode', desc: 'Target power training.', color: 'text-neon-purple', gradient: 'from-neon-purple/20 to-transparent' },
          { id: 'EDITOR', icon: BarChart2, title: 'Workouts', desc: 'Custom interval builder.', color: 'text-neon-green', gradient: 'from-neon-green/20 to-transparent' }
        ].map((item) => (
          <Card 
            key={item.id}
            onClick={() => {
                if(item.id === 'FREE_RIDE') updateResistance(2);
                if(item.id === 'ERG_MODE') updateTargetPower(150);
                setView(item.id as ViewState);
            }}
            className={`p-10 group transition-all duration-500 hover:scale-[1.03]`}
          >
              <div className={`absolute inset-0 bg-gradient-to-br ${item.gradient} opacity-0 group-hover:opacity-100 transition-opacity duration-500`}></div>
              <div className="relative z-10">
                  <div className={`mb-8 w-16 h-16 rounded-3xl bg-white/5 flex items-center justify-center group-hover:bg-white/10 transition-colors border border-white/5 group-hover:border-white/20 shadow-lg`}>
                      <item.icon size={32} className={`${item.color} drop-shadow-[0_0_8px_rgba(255,255,255,0.3)]`} />
                  </div>
                  <h3 className="text-3xl font-bold mb-3 text-white group-hover:translate-x-1 transition-transform">{item.title}</h3>
                  <p className="text-gray-400 text-sm leading-relaxed mb-8">{item.desc}</p>
                  <div className="flex items-center text-sm font-bold text-white/50 group-hover:text-white transition-colors uppercase tracking-widest">
                      Enter <ArrowRight size={16} className="ml-2 group-hover:translate-x-2 transition-transform"/>
                  </div>
              </div>
          </Card>
        ))}
      </div>
    </div>
  );

  const renderFreeRide = () => (
    <div className="flex flex-col h-full max-w-6xl mx-auto w-full pt-8 animate-slide-up">
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
            <StatBox label="Power" value={trainerData.power} unit="W" color="#3b82f6" />
            <StatBox label="Cadence" value={Math.round(trainerData.cadence)} unit="RPM" color="#06b6d4" />
            <StatBox label="Heart Rate" value={hrData.heartRate || '--'} unit="BPM" color="#ec4899" />
        </div>

        <LiveGraph />

        <div className="mt-8">
            <Card className="p-8">
                <div className="flex justify-between mb-6">
                    <span className="font-mono text-gray-400 font-bold uppercase">Slope Resistance</span>
                    <span className="font-mono font-bold text-neon-cyan text-xl">{resistanceLevel * 10}%</span>
                </div>
                <input 
                    type="range" 
                    min="1" 
                    max="10" 
                    value={resistanceLevel}
                    onChange={(e) => updateResistance(parseInt(e.target.value))}
                    className="w-full h-3 bg-gray-800 rounded-lg appearance-none cursor-pointer accent-neon-cyan hover:accent-neon-blue transition-all"
                />
                <div className="flex justify-between mt-4 text-xs font-mono text-gray-500 uppercase">
                    <span>Flat (10%)</span>
                    <span>Wall (100%)</span>
                </div>
            </Card>
        </div>
    </div>
  );

  const renderErgMode = () => (
    <div className="flex flex-col h-full max-w-6xl mx-auto w-full pt-8 animate-slide-up">
        <div className="flex justify-center mb-10">
             <div className="relative">
                 <div className="absolute inset-0 bg-neon-purple/20 blur-[80px] rounded-full animate-pulse-slow"></div>
                 <div className="text-center relative z-10">
                     <div className="text-[140px] font-mono font-bold text-white leading-none tracking-tighter drop-shadow-[0_0_25px_rgba(139,92,246,0.5)]">
                        {trainerData.power}
                     </div>
                     <div className="text-neon-purple font-mono font-bold tracking-[0.4em] uppercase mt-2">Current Watts</div>
                 </div>
             </div>
        </div>

        <LiveGraph />

        <Card className="mt-8 p-10 text-center bg-gradient-to-b from-idx-surface to-black/80 border-white/10">
            <span className="font-mono text-gray-500 font-bold uppercase block mb-8 text-xs tracking-[0.2em]">Target Power Control</span>
            
            <div className="flex items-center justify-center gap-12 mb-12">
                <button 
                    onClick={() => updateTargetPower(Math.max(50, targetPower - 10))}
                    className="w-24 h-24 rounded-full bg-white/5 hover:bg-white/10 border border-white/10 hover:border-white/30 flex items-center justify-center transition-all active:scale-95 group"
                >
                    <Plus size={40} className="rotate-45 text-gray-400 group-hover:text-white transition-colors" />
                </button>
                <div className="relative min-w-[200px]">
                    <div className="text-8xl font-mono font-bold text-transparent bg-clip-text bg-gradient-to-b from-white to-gray-400 tabular-nums drop-shadow-xl">
                        {targetPower}
                    </div>
                    <div className="text-sm text-gray-500 font-bold absolute top-2 -right-6">W</div>
                </div>
                <button 
                    onClick={() => updateTargetPower(Math.min(1000, targetPower + 10))}
                    className="w-24 h-24 rounded-full bg-neon-blue/10 hover:bg-neon-blue/20 border border-neon-blue/30 hover:border-neon-blue flex items-center justify-center transition-all active:scale-95 shadow-[0_0_30px_rgba(59,130,246,0.2)] hover:shadow-[0_0_50px_rgba(59,130,246,0.4)] group"
                >
                    <Plus size={40} className="text-neon-blue group-hover:text-white transition-colors" />
                </button>
            </div>
            
            <div className="flex flex-wrap justify-center gap-4">
                {[100, 150, 200, 250, 300].map(w => (
                    <button 
                        key={w} 
                        onClick={() => updateTargetPower(w)}
                        className={`px-8 py-4 rounded-2xl font-mono font-bold transition-all border ${targetPower === w ? 'bg-neon-purple text-white border-neon-purple shadow-[0_0_20px_rgba(139,92,246,0.5)] scale-105' : 'bg-white/5 text-gray-400 border-white/5 hover:bg-white/10 hover:border-white/20'}`}
                    >
                        {w}w
                    </button>
                ))}
            </div>
        </Card>
    </div>
  );

  const renderEditor = () => {
    // Helper to add interval
    const addStep = (type: 'steady' | 'ramp', zoneIndex: number, label: string) => {
        const zone = ZONES[zoneIndex];
        const factor = (zone.min + (zone.max > 2 ? 1.5 : zone.max)) / 2; 
        const safeFactor = factor === 0 ? 0.4 : factor;
        const power = Math.round(ftp * safeFactor);
        
        let step: IntervalStep = {
          id: Math.random().toString(36).substr(2, 9),
          type: type, duration: 300, targetPower: power, description: label || zone.label
        };
    
        if (type === 'ramp') {
            if (label === 'Warm up') {
                step.startPower = Math.round(ftp * 0.40); step.targetPower = Math.round(ftp * 0.75); step.duration = 600;
            } else if (label === 'Cool down') {
                step.startPower = Math.round(ftp * 0.75); step.targetPower = Math.round(ftp * 0.40); step.duration = 300;
            }
        }
        setWorkout(w => ({ ...w, steps: [...w.steps, step] }));
        setSelectedStepId(step.id);
    };

    const getRoundedPath = (x: number, width: number, y1: number, y2: number) => {
        const h1 = 100 - y1;
        const h2 = 100 - y2;
        const r = Math.min(2, h1/2, h2/2, width/2); // Radius logic
        
        const dx = width;
        const dy = y2 - y1;
        const len = Math.sqrt(dx*dx + dy*dy);
        const ux = len === 0 ? 0 : dx / len;
        const uy = len === 0 ? 0 : dy / len;
        
        // M BL -> L TL_start -> Q TL -> L TR_start -> Q TR -> L BR -> Z
        let d = `M ${x},100 `;
        d += `L ${x},${y1 + r} `;
        d += `Q ${x},${y1} ${x + r*ux},${y1 + r*uy} `;
        d += `L ${x + width - r*ux},${y2 - r*uy} `;
        d += `Q ${x + width},${y2} ${x + width},${y2 + r} `;
        d += `L ${x + width},100 Z`;
        return d;
    };

    const renderGraph = () => {
        if (workout.steps.length === 0) return (
            <div className="flex flex-col items-center justify-center h-full text-gray-600 space-y-4">
                <div className="w-24 h-24 rounded-full bg-white/5 flex items-center justify-center mb-2 animate-pulse border border-white/5">
                    <BarChart2 size={40} className="opacity-40"/>
                </div>
                <p className="font-mono text-sm tracking-widest uppercase">Workout Empty</p>
                <p className="text-xs text-gray-500">Select a zone below to construct sequence</p>
            </div>
        )
        const maxPower = Math.max(...workout.steps.map(s => Math.max(s.targetPower, s.startPower || 0)));
        const yMax = Math.max(maxPower * 1.1, ftp * 1.5);
        let currentX = 0;

        return (
          <svg width="100%" height="100%" viewBox="0 0 100 100" preserveAspectRatio="none" className="overflow-visible">
            <defs>
              {ZONES.map((z) => (
                <linearGradient key={z.name} id={`grad-${z.name}`} x1="0" y1="0" x2="0" y2="1">
                  <stop offset="0%" stopColor={z.gradient[0]} stopOpacity="0.9" />
                  <stop offset="100%" stopColor={z.gradient[1]} stopOpacity="0.2" />
                </linearGradient>
              ))}
              <filter id="neon-glow" x="-50%" y="-50%" width="200%" height="200%">
                 <feGaussianBlur stdDeviation="1" result="coloredBlur"/>
                 <feMerge>
                    <feMergeNode in="coloredBlur"/>
                    <feMergeNode in="SourceGraphic"/>
                 </feMerge>
              </filter>
            </defs>
            
            {ZONES.slice(0, 5).map((z, i) => {
               const y = 100 - (z.max * ftp / yMax * 100);
               return (
                 <line key={z.name} x1="0" y1={y} x2="100" y2={y} stroke="rgba(255,255,255,0.1)" strokeWidth="0.5" strokeDasharray="2 2" vectorEffect="non-scaling-stroke"/>
               );
            })}

            {workout.steps.map((step, index) => {
              const widthPct = (step.duration / workout.totalDuration) * 100;
              const startP = step.type === 'ramp' && step.startPower ? step.startPower : step.targetPower;
              const endP = step.targetPower;
              const yStart = 100 - ((startP / yMax) * 100);
              const yEnd = 100 - ((endP / yMax) * 100);
              
              const avgPower = (startP + endP) / 2;
              const zone = getZoneColor(avgPower, ftp);
              const isSelected = step.id === selectedStepId;
              
              const pathD = getRoundedPath(currentX, widthPct, yStart, yEnd);

              const element = (
                <g key={step.id} onClick={() => setSelectedStepId(step.id)} className="cursor-pointer group">
                   <path 
                     d={pathD}
                     fill={`url(#grad-${zone.name})`} 
                     stroke="white"
                     strokeWidth={1.5}
                     vectorEffect="non-scaling-stroke"
                     className={`transition-all duration-300 ${isSelected ? 'opacity-100' : 'opacity-90 group-hover:opacity-100'}`}
                     style={{ filter: isSelected ? 'drop-shadow(0 0 5px white)' : '' }}
                   />
                </g>
              );
              currentX += widthPct;
              return element;
            })}
          </svg>
        );
    }

    return (
        <div className="h-full flex flex-col gap-6 animate-fade-in max-w-6xl mx-auto w-full">
            <div className="flex flex-wrap gap-4 items-center mb-4">
                <div className="flex-1 bg-white/5 rounded-2xl p-3 px-5 border border-white/5 flex items-center gap-3 backdrop-blur-md">
                    <Edit3 size={18} className="text-gray-400"/>
                    <input 
                        value={workout.name} 
                        onChange={(e) => setWorkout({...workout, name: e.target.value})}
                        className="bg-transparent text-2xl font-bold text-white focus:outline-none w-full placeholder-gray-600"
                        placeholder="Workout Name..."
                    />
                </div>
                <div className="flex gap-4">
                    <div className="bg-white/5 rounded-2xl p-3 px-5 border border-white/5 backdrop-blur-md">
                        <label className="text-[10px] text-gray-500 font-bold uppercase block">FTP Target</label>
                        <div className="flex items-center gap-1">
                            <input type="number" value={ftp} onChange={(e) => setFtp(parseInt(e.target.value) || 0)} className="bg-transparent font-mono text-xl font-bold text-neon-blue w-16 focus:outline-none"/>
                            <span className="text-xs text-gray-400">W</span>
                        </div>
                    </div>
                    <div className="bg-white/5 rounded-2xl p-3 px-5 border border-white/5 backdrop-blur-md">
                         <label className="text-[10px] text-gray-500 font-bold uppercase block">Duration</label>
                         <div className="text-xl font-mono font-bold text-white">{formatTime(workout.totalDuration)}</div>
                    </div>
                </div>
            </div>

            <Card className="h-[450px] relative flex flex-col p-8 bg-gradient-to-b from-idx-surface/80 to-black/90 border-white/10" glow>
                <div className="flex-1 w-full h-full z-10">{renderGraph()}</div>
                
                {workout.steps.length > 0 && (
                     <button onClick={(e) => { e.stopPropagation(); setIsConfirmingClear(!isConfirmingClear ? true : false); if(isConfirmingClear) { setWorkout(w => ({...w, steps: [], totalDuration: 0})); setSelectedStepId(null); setIsConfirmingClear(false); } }} 
                        className={`absolute top-6 right-6 z-20 flex items-center gap-2 text-xs font-bold px-4 py-2 rounded-xl transition-all border shadow-lg ${isConfirmingClear ? "bg-red-500/20 text-red-400 border-red-500" : "bg-black/40 text-gray-400 border-white/10 hover:text-white hover:bg-white/5"}`}
                     >
                        <Trash2 size={14} /> {isConfirmingClear ? "Confirm?" : "Clear"}
                     </button>
                )}
                
                {selectedStepId && (
                     <div className="absolute bottom-6 left-1/2 -translate-x-1/2 bg-black/90 backdrop-blur-xl border border-white/20 p-4 rounded-2xl shadow-2xl flex items-center gap-6 z-30 animate-slide-up ring-1 ring-white/10">
                         {['duration', 'targetPower'].map(field => (
                             <div key={field} className="flex flex-col items-center">
                                <label className="text-[10px] text-gray-500 font-bold block uppercase mb-1">{field === 'duration' ? 'Secs' : 'Watts'}</label>
                                <input type="number" className="bg-white/5 rounded-lg text-white w-20 p-1 text-center font-mono font-bold border border-white/10 focus:border-neon-blue focus:bg-white/10 outline-none transition-colors"
                                    value={(workout.steps.find(s=>s.id === selectedStepId) as any)?.[field]}
                                    onChange={(e) => {
                                        const val = parseInt(e.target.value);
                                        setWorkout(w => ({...w, steps: w.steps.map(s => s.id === selectedStepId ? {...s, [field]: val} : s)}))
                                    }}
                                />
                             </div>
                         ))}
                         <div className="h-8 w-px bg-white/10"></div>
                         <button onClick={() => { setWorkout(w => ({...w, steps: w.steps.filter(s => s.id !== selectedStepId)})); setSelectedStepId(null); }} className="p-2 hover:bg-red-500/20 hover:text-red-400 text-gray-400 rounded-lg transition-colors"><Trash2 size={18} /></button>
                         <button onClick={() => setSelectedStepId(null)} className="p-2 hover:bg-white/10 hover:text-white text-gray-400 rounded-lg transition-colors"><X size={18} /></button>
                     </div>
                )}
            </Card>

            <div className="grid grid-cols-2 md:grid-cols-8 gap-3 mt-2">
                <button onClick={() => addStep('ramp', 0, 'Warm up')} className="h-24 rounded-2xl bg-white/5 border border-white/5 hover:bg-white/10 hover:border-white/20 transition-all flex flex-col items-center justify-center gap-2 group">
                    <span className="text-[10px] font-bold uppercase tracking-widest text-gray-400 group-hover:text-white">Warm Up</span>
                    <div className="w-12 h-1.5 bg-gradient-to-r from-gray-700 to-gray-400 rounded-full"></div>
                </button>
                
                {ZONES.map((z, i) => (
                    <button key={z.name} onClick={() => addStep('steady', i, '')} 
                        className="relative h-24 rounded-2xl border border-white/5 transition-all group overflow-hidden hover:-translate-y-1 hover:shadow-lg"
                        style={{ backgroundColor: `${z.color}10` }}
                    >
                        {/* Glow Effect */}
                        <div className="absolute inset-0 opacity-0 group-hover:opacity-100 transition-opacity duration-500 bg-gradient-to-b from-transparent to-white/5"></div>
                        <div className="absolute bottom-0 left-0 right-0 h-1.5 transition-all group-hover:h-full group-hover:opacity-10" style={{ backgroundColor: z.color }}></div>
                        
                        <div className="flex flex-col items-center justify-center h-full relative z-10">
                            <span className="text-xl font-black text-white drop-shadow-md mb-1">{z.name}</span>
                            <div className="px-2 py-0.5 rounded bg-black/40 border border-white/5 backdrop-blur-sm">
                                <span className="text-[10px] text-gray-300 font-mono font-bold">{Math.round(ftp*z.min)}-{Math.round(ftp*(z.max>2?2:z.max))}w</span>
                            </div>
                        </div>
                        {/* Neon border on hover */}
                        <div className="absolute inset-0 border-2 border-transparent group-hover:border-white/20 rounded-2xl transition-all"></div>
                    </button>
                ))}
                
                <button onClick={() => addStep('ramp', 0, 'Cool down')} className="h-24 rounded-2xl bg-white/5 border border-white/5 hover:bg-white/10 hover:border-white/20 transition-all flex flex-col items-center justify-center gap-2 group">
                    <span className="text-[10px] font-bold uppercase tracking-widest text-gray-400 group-hover:text-white">Cool Down</span>
                    <div className="w-12 h-1.5 bg-gradient-to-r from-gray-400 to-gray-700 rounded-full"></div>
                </button>
            </div>

            <div className="flex justify-end pt-4 pb-8">
                <Button 
                    onClick={() => {
                        if (workout.steps.length === 0) return;
                        setSession({ isActive: true, currentStepIndex: 0, elapsedTimeInStep: 0, totalElapsedTime: 0, isPaused: false });
                        const firstStep = workout.steps[0];
                        bleService.setTargetPower(firstStep.type === 'ramp' && firstStep.startPower ? firstStep.startPower : firstStep.targetPower);
                        setView('SESSION');
                    }}
                    disabled={workout.steps.length === 0}
                    className="w-full md:w-auto px-16 py-5 text-xl bg-gradient-to-r from-neon-green via-neon-cyan to-neon-blue shadow-[0_0_30px_rgba(16,185,129,0.3)] hover:shadow-[0_0_50px_rgba(16,185,129,0.5)]"
                >
                    <Play size={24} fill="currentColor" /> INITIATE
                </Button>
            </div>
        </div>
    );
  };

  const renderSession = () => (
      <div className="flex flex-col h-full gap-8 max-w-6xl mx-auto w-full pt-8 animate-fade-in">
          <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
              <StatBox label="Power" value={trainerData.power} unit="W" color="#3b82f6" />
              <StatBox label="Cadence" value={Math.round(trainerData.cadence)} unit="RPM" color="#06b6d4" />
              <StatBox label="Heart Rate" value={hrData.heartRate || '--'} unit="BPM" color="#ec4899" />
              <StatBox label="Target" value={workout.steps[session.currentStepIndex]?.type === 'ramp' ? '~' : workout.steps[session.currentStepIndex]?.targetPower} unit="W" color="#10b981" />
          </div>

          <div className="flex-1 relative">
             <Card className="h-[450px] p-0 overflow-hidden relative border-neon-blue/20 shadow-[0_0_60px_-10px_rgba(59,130,246,0.15)] bg-gradient-to-b from-idx-surface to-black" glow>
                 <div className="absolute top-8 left-8 z-10">
                      <h2 className="text-4xl font-black text-white tracking-tight drop-shadow-lg mb-2">{workout.steps[session.currentStepIndex]?.description}</h2>
                      <div className="flex items-center gap-3 bg-black/40 px-3 py-1.5 rounded-lg border border-white/5 w-fit">
                          <span className="w-2.5 h-2.5 bg-neon-green rounded-full animate-pulse shadow-[0_0_10px_#10b981]"></span>
                          <p className="text-gray-300 font-mono text-sm font-bold">Step {session.currentStepIndex + 1} <span className="text-gray-600">/</span> {workout.steps.length}</p>
                      </div>
                 </div>
                 
                 <div className="absolute top-8 right-8 z-10 text-right">
                      <div className="text-7xl font-mono font-bold text-white tabular-nums tracking-tighter drop-shadow-2xl">
                          {formatTime(workout.steps[session.currentStepIndex]?.duration - session.elapsedTimeInStep)}
                      </div>
                      <div className="text-sm text-neon-blue font-bold uppercase tracking-[0.3em] mt-2 opacity-80">Remaining</div>
                 </div>

                 <div className="w-full h-full pt-28">
                    <ResponsiveContainer width="100%" height="100%">
                        <AreaChart data={workout.steps.flatMap((step, i) => {
                            const start = workout.steps.slice(0, i).reduce((a,b)=>a+b.duration,0);
                            const sP = step.type === 'ramp' && step.startPower ? step.startPower : step.targetPower;
                            const eP = step.targetPower;
                            return [{ time: start, power: sP }, { time: start + step.duration, power: eP }];
                        })}>
                            <defs>
                                <linearGradient id="sessionFill" x1="0" y1="0" x2="0" y2="1">
                                    <stop offset="0%" stopColor="#3b82f6" stopOpacity={0.6}/>
                                    <stop offset="100%" stopColor="#8b5cf6" stopOpacity={0.1}/>
                                </linearGradient>
                                <filter id="glow-line" x="-50%" y="-50%" width="200%" height="200%">
                                    <feGaussianBlur stdDeviation="4" result="coloredBlur"/>
                                    <feMerge>
                                        <feMergeNode in="coloredBlur"/>
                                        <feMergeNode in="SourceGraphic"/>
                                    </feMerge>
                                </filter>
                            </defs>
                            <XAxis dataKey="time" hide />
                            <YAxis domain={[0, 'dataMax + 100']} hide />
                            <Area 
                                type="stepAfter" 
                                dataKey="power" 
                                stroke="#ffffff" 
                                strokeWidth={4} 
                                fill="url(#sessionFill)" 
                                isAnimationActive={false} 
                                style={{ filter: 'url(#glow-line)' }}
                            />
                        </AreaChart>
                    </ResponsiveContainer>
                    
                    {/* Progress Cursor */}
                    <div 
                        className="absolute top-0 bottom-0 w-0.5 bg-white shadow-[0_0_20px_white] z-20 transition-all duration-1000 ease-linear mix-blend-screen"
                        style={{ left: `${(session.totalElapsedTime / workout.totalDuration) * 100}%` }}
                    >
                        <div className="absolute top-0 -left-[5px] w-3 h-3 bg-white rounded-full shadow-[0_0_15px_white]"></div>
                        <div className="absolute bottom-0 -left-[5px] w-3 h-3 bg-white rounded-full shadow-[0_0_15px_white]"></div>
                    </div>
                 </div>
             </Card>
          </div>

          <LiveGraph />

          <div className="flex justify-center gap-8 pb-10">
                <button onClick={() => setSession(s => ({...s, isPaused: !s.isPaused}))} 
                    className="w-24 h-24 rounded-full bg-white text-black hover:scale-110 transition-transform flex items-center justify-center shadow-[0_0_40px_rgba(255,255,255,0.4)]"
                >
                    {session.isPaused ? <Play size={40} fill="black" /> : <Pause size={40} fill="black" />}
                </button>
                <button onClick={() => { bleService.setTargetPower(100); setView('EDITOR'); setSession(s => ({...s, isActive: false})); }} 
                    className="w-24 h-24 rounded-full bg-red-500/10 border border-red-500/50 text-red-500 hover:bg-red-500 hover:text-white hover:scale-110 transition-all flex items-center justify-center shadow-[0_0_30px_rgba(239,68,68,0.2)]"
                >
                    <div className="w-8 h-8 bg-current rounded-sm"></div>
                </button>
          </div>
      </div>
  );

  // --- Main Layout ---

  return (
    <div className="min-h-screen font-sans selection:bg-neon-blue selection:text-white flex flex-col relative overflow-hidden text-gray-200">
      
      {/* Navbar */}
      <header className="border-b border-white/5 bg-idx-bg/60 backdrop-blur-xl p-5 sticky top-0 z-50 transition-all">
        <div className="max-w-7xl mx-auto flex justify-between items-center">
          <div className="flex items-center gap-6">
            {view !== 'HOME' && (
                <button onClick={() => setView('HOME')} className="text-gray-400 hover:text-white hover:bg-white/10 p-2.5 rounded-xl transition-all">
                    <Home size={22} />
                </button>
            )}
            <div className="flex items-center gap-3 select-none">
                <div className="w-9 h-9 rounded-xl bg-gradient-to-tr from-neon-blue to-neon-purple flex items-center justify-center text-white shadow-[0_0_15px_rgba(59,130,246,0.5)]">
                   <Activity size={20} />
                </div>
                <h1 className="text-lg font-bold tracking-tight text-white hidden sm:block">
                  Your training, <span className="text-transparent bg-clip-text bg-gradient-to-r from-neon-blue to-neon-cyan">your way</span>
                </h1>
            </div>
          </div>
          
          <div className="flex items-center gap-4">
              <div className="hidden md:flex items-center gap-3 text-xs font-mono font-bold text-gray-500 bg-black/40 px-4 py-2 rounded-full border border-white/5 shadow-inner">
                 <div className="flex items-center gap-2">
                    <span className={`w-2 h-2 rounded-full ${isTrainerConnected ? 'bg-neon-green shadow-[0_0_8px_#10b981]' : 'bg-red-500'}`}></span>
                    <span className={isTrainerConnected ? 'text-gray-200' : ''}>TRAINER</span>
                 </div>
                 <span className="text-gray-700 mx-1">/</span>
                 <div className="flex items-center gap-2">
                    <span className={`w-2 h-2 rounded-full ${isHRConnected ? 'bg-neon-pink shadow-[0_0_8px_#ec4899]' : 'bg-red-500'}`}></span>
                    <span className={isHRConnected ? 'text-gray-200' : ''}>HRM</span>
                 </div>
              </div>

              <div className="flex gap-2">
                 <button onClick={handleConnectTrainer} className={`p-2.5 rounded-xl transition-all ${isTrainerConnected ? 'text-neon-green bg-neon-green/10 ring-1 ring-neon-green/30' : 'text-gray-400 hover:text-white hover:bg-white/5'}`}><Zap size={20}/></button>
                 <button onClick={handleConnectHR} className={`p-2.5 rounded-xl transition-all ${isHRConnected ? 'text-neon-pink bg-neon-pink/10 ring-1 ring-neon-pink/30' : 'text-gray-400 hover:text-white hover:bg-white/5'}`}><Heart size={20}/></button>
              </div>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 w-full p-4 md:p-8 overflow-y-auto custom-scrollbar relative z-0">
        {view === 'HOME' && renderHome()}
        {view === 'FREE_RIDE' && renderFreeRide()}
        {view === 'ERG_MODE' && renderErgMode()}
        {view === 'EDITOR' && renderEditor()}
        {view === 'SESSION' && renderSession()}
      </main>
    </div>
  );
}

export default App;
